export enum FlightClass {
  ECONOMY = 'Economy',
  BUSINESS = 'Business',
  FIRST = 'First'
}

export enum TripType {
  ONE_WAY = 'One Way',
  ROUND_TRIP = 'Round Trip'
}

export interface Airport {
  code: string;
  city: string;
  name: string;
  country: string;
}

export interface Flight {
  id: string;
  airline: string;
  airlineLogo: string;
  flightNumber: string;
  departureTime: string; // ISO string
  arrivalTime: string; // ISO string
  origin: string; // Airport code
  destination: string; // Airport code
  price: number;
  duration: string;
  stops: number;
  class: FlightClass;
}

export interface Passenger {
  firstName: string;
  lastName: string;
  passportNumber?: string;
  nationality?: string;
  email: string;
  phone: string;
}

export interface Booking {
  id: string;
  flightId: string;
  flight: Flight;
  passenger: Passenger;
  status: 'CONFIRMED' | 'PENDING' | 'CANCELLED';
  bookingDate: string;
  pnr: string;
  totalAmount: number;
}

export interface SearchParams {
  from: string;
  to: string;
  date: string;
  passengers: number;
  class: FlightClass;
  tripType: TripType;
}

export interface AIRecommendation {
  destination: string;
  description: string;
  attractions: string[];
  food: string;
}

import { Flight, FlightClass, Airport, Booking, Passenger, SearchParams } from '../types';

// Mock Data
export const AIRPORTS: Airport[] = [
  { code: 'DAC', city: 'Dhaka', name: 'Hazrat Shahjalal Intl', country: 'Bangladesh' },
  { code: 'CXB', city: 'Cox\'s Bazar', name: 'Cox\'s Bazar Airport', country: 'Bangladesh' },
  { code: 'JFK', city: 'New York', name: 'John F. Kennedy Intl', country: 'USA' },
  { code: 'LHR', city: 'London', name: 'Heathrow Airport', country: 'UK' },
  { code: 'DXB', city: 'Dubai', name: 'Dubai Intl', country: 'UAE' },
  { code: 'SIN', city: 'Singapore', name: 'Changi Airport', country: 'Singapore' },
  { code: 'BKK', city: 'Bangkok', name: 'Suvarnabhumi Airport', country: 'Thailand' },
];

const AIRLINES = [
  { name: 'Biman Bangladesh', logo: 'https://picsum.photos/id/1/40/40' },
  { name: 'US-Bangla', logo: 'https://picsum.photos/id/2/40/40' },
  { name: 'Emirates', logo: 'https://picsum.photos/id/3/40/40' },
  { name: 'Singapore Air', logo: 'https://picsum.photos/id/4/40/40' },
];

// Helper to generate mock flights
const generateFlights = (from: string, to: string, date: string): Flight[] => {
  const results: Flight[] = [];
  const numFlights = Math.floor(Math.random() * 5) + 3; // 3 to 7 flights

  for (let i = 0; i < numFlights; i++) {
    const airline = AIRLINES[Math.floor(Math.random() * AIRLINES.length)];
    const priceBase = 50 + Math.random() * 500;
    const hour = Math.floor(Math.random() * 24);
    const durationHours = Math.floor(Math.random() * 10) + 1;

    const dep = new Date(date);
    dep.setHours(hour, 0, 0);

    const arr = new Date(dep);
    arr.setHours(hour + durationHours);

    results.push({
      id: `FL-${Math.random().toString(36).substr(2, 9)}`,
      airline: airline.name,
      airlineLogo: airline.logo,
      flightNumber: `${airline.name.substring(0, 2).toUpperCase()}${Math.floor(Math.random() * 999)}`,
      departureTime: dep.toISOString(),
      arrivalTime: arr.toISOString(),
      origin: from,
      destination: to,
      price: Math.floor(priceBase * (from === 'DAC' ? 1 : 2.5)), // Simple pricing logic
      duration: `${durationHours}h 00m`,
      stops: Math.random() > 0.7 ? 1 : 0,
      class: FlightClass.ECONOMY,
    });
  }
  return results.sort((a, b) => a.price - b.price);
};

// Simulated API Calls
export const searchFlights = async (params: SearchParams): Promise<Flight[]> => {
  return new Promise((resolve) => {
    setTimeout(() => {
      resolve(generateFlights(params.from, params.to, params.date));
    }, 800);
  });
};

export const createBooking = async (flight: Flight, passenger: Passenger): Promise<Booking> => {
  return new Promise((resolve) => {
    setTimeout(() => {
      const booking: Booking = {
        id: `BK-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
        flightId: flight.id,
        flight: flight,
        passenger: passenger,
        status: 'CONFIRMED',
        bookingDate: new Date().toISOString(),
        pnr: Math.random().toString(36).substr(2, 6).toUpperCase(),
        totalAmount: flight.price
      };

      // Persist to local storage for "Admin" view
      const existing = JSON.parse(localStorage.getItem('bookings') || '[]');
      localStorage.setItem('bookings', JSON.stringify([booking, ...existing]));

      resolve(booking);
    }, 1500);
  });
};

export const getBookings = async (): Promise<Booking[]> => {
  return new Promise((resolve) => {
    const existing = JSON.parse(localStorage.getItem('bookings') || '[]');
    resolve(existing);
  });
};

export const getStats = async () => {
    const bookings = await getBookings();
    const totalRevenue = bookings.reduce((sum, b) => sum + b.totalAmount, 0);
    return {
        totalBookings: bookings.length,
        revenue: totalRevenue,
        pending: bookings.filter(b => b.status === 'PENDING').length
    }
}

import { GoogleGenAI, Type } from "@google/genai";
import { AIRecommendation } from "../types";

// Initialize Gemini
// Note: In a real production app, ensure this is behind a backend proxy if possible,
// or strictly use env variables as requested.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getDestinationRecommendations = async (destination: string): Promise<AIRecommendation | null> => {
  try {
    const model = "gemini-3-flash-preview"; 

    // Fallback if no API key is present to prevent app crash during demo
    if (!process.env.API_KEY) {
        console.warn("Gemini API Key missing. Returning mock data.");
        return {
            destination: destination,
            description: "A beautiful place waiting to be explored (AI Mock).",
            attractions: ["Central Park", "Old Town", "The Grand Museum"],
            food: "Local Street Food"
        };
    }

    const prompt = `Provide travel recommendations for ${destination}. 
    Return a JSON object with the following fields:
    - destination (string)
    - description (string, max 30 words)
    - attractions (array of 3 strings)
    - food (string, one famous dish)
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
            type: Type.OBJECT,
            properties: {
                destination: { type: Type.STRING },
                description: { type: Type.STRING },
                attractions: { 
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                },
                food: { type: Type.STRING }
            }
        }
      }
    });

    const text = response.text;
    if (!text) return null;

    return JSON.parse(text) as AIRecommendation;

  } catch (error) {
    console.error("AI Service Error:", error);
    return null;
  }
};

