import React, { useState } from 'react';
import Layout from './components/Layout';
import HomePage from './pages/HomePage';
import SearchResultsPage from './pages/SearchResultsPage';
import BookingPage from './pages/BookingPage';
import ConfirmationPage from './pages/ConfirmationPage';
import AdminDashboard from './pages/AdminDashboard';
import { SearchParams, Flight } from './types';

// Simple router state
type ViewState = 'home' | 'search' | 'booking' | 'confirmation' | 'admin' | 'dashboard';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [searchParams, setSearchParams] = useState<SearchParams | null>(null);
  const [selectedFlight, setSelectedFlight] = useState<Flight | null>(null);
  const [confirmedBookingId, setConfirmedBookingId] = useState<string>('');

  const navigateTo = (view: ViewState) => {
    setCurrentView(view);
    window.scrollTo(0, 0);
  };

  const handleSearch = (params: SearchParams) => {
    setSearchParams(params);
    navigateTo('search');
  };

  const handleSelectFlight = (flight: Flight) => {
    setSelectedFlight(flight);
    navigateTo('booking');
  };

  const handleBookingSuccess = (bookingId: string) => {
    setConfirmedBookingId(bookingId);
    navigateTo('confirmation');
  };

  const renderContent = () => {
    switch (currentView) {
      case 'home':
        return <HomePage onSearch={handleSearch} />;
      case 'search':
        return searchParams ? (
          <SearchResultsPage 
            params={searchParams} 
            onSelectFlight={handleSelectFlight}
            onBack={() => navigateTo('home')}
          />
        ) : <HomePage onSearch={handleSearch} />;
      case 'booking':
        return selectedFlight ? (
          <BookingPage 
            flight={selectedFlight} 
            onSuccess={handleBookingSuccess}
            onBack={() => navigateTo('search')}
          />
        ) : null;
      case 'confirmation':
        return <ConfirmationPage bookingId={confirmedBookingId} onHome={() => navigateTo('home')} />;
      case 'admin':
        return <AdminDashboard />;
      case 'dashboard':
        return <AdminDashboard />; // Reusing admin view as dashboard for demo simplicity
      default:
        return <HomePage onSearch={handleSearch} />;
    }
  };

  return (
    <Layout onNavigate={(page) => navigateTo(page as ViewState)} currentPage={currentView}>
      {renderContent()}
    </Layout>
  );
};

export default App;

